custom_css:
@import url("https://fontsapi.zeoseven.com/217/main/result.css");

body {
    font-family: "CLFN 24x CN";
    font-weight: normal;
}

/* * Pixel Cyberpunk "Icelandic Black Sand" - Enhanced Wide Edition
 * 特点：全屏适配、厚重毛玻璃、无滚动条、像素 UI
 */

:root {
    --pixel-bg: rgba(5, 5, 10, 0.85); /* 更深邃的底色 */
    --pixel-border: rgba(79, 211, 196, 0.8); 
    --pixel-accent: rgba(138, 79, 255, 0.9); 
    --pixel-text: rgba(224, 224, 224, 0.95);
    --glass-heavy: blur(15px) saturate(150%); /* 厚重毛玻璃核心参数 */
    --glass-bg: rgba(15, 15, 20, 0.75);
}

/* --- 1. 隐藏全局滚动条 --- */
*::-webkit-scrollbar {
    display: none !important;
    width: 0 !important;
}
* {
    -ms-overflow-style: none !important;
    scrollbar-width: none !important;
}

/* --- 2. CRT 扫描线背景 --- */
body::before {
    content: " ";
    display: block;
    position: fixed;
    top: 0; left: 0; bottom: 0; right: 0;
    background: linear-gradient(rgba(18, 16, 16, 0.1) 50%, rgba(0, 0, 0, 0) 50%), 
                linear-gradient(90deg, rgba(255, 0, 0, 0.02), rgba(0, 255, 0, 0.01), rgba(0, 0, 255, 0.02));
    z-index: 9999;
    background-size: 100% 3px, 3px 100%;
    pointer-events: none;
    opacity: 0.3;
}

/* --- 3. 聊天气泡：宽屏 + 厚重毛玻璃 --- */
.mes {
    background: var(--glass-bg) !important;
    backdrop-filter: var(--glass-heavy) !important;
    -webkit-backdrop-filter: var(--glass-heavy) !important;
    border: 3px solid var(--pixel-border) !important;

    /* 宽屏设置 */
    margin: 20px auto !important;
    width: 92% !important; 
    max-width: 1200px !important;

    padding: 25px !important;
    display: flex !important;
    flex-direction: column !important;
    align-items: center !important;
    image-rendering: pixelated;
    position: relative;
    box-shadow: 0 10px 30px rgba(0,0,0,0.5);

    /* 像素切割角 */
    clip-path: polygon(
        0 12px, 4px 12px, 4px 8px, 8px 8px, 8px 4px, 12px 4px, 12px 0,
        calc(100% - 12px) 0, calc(100% - 12px) 4px, calc(100% - 8px) 4px, calc(100% - 8px) 8px, calc(100% - 4px) 8px, calc(100% - 4px) 12px, 100% 12px,
        100% calc(100% - 12px), calc(100% - 4px) calc(100% - 12px), calc(100% - 4px) calc(100% - 8px), calc(100% - 8px) calc(100% - 8px), calc(100% - 8px) calc(100% - 4px), calc(100% - 12px) calc(100% - 4px), calc(100% - 12px) 100%,
        12px 100%, 12px calc(100% - 4px), 8px calc(100% - 4px), 8px calc(100% - 8px), 4px calc(100% - 8px), 4px calc(100% - 12px), 0 calc(100% - 12px)
    );
}

.user_mes {
    border-color: var(--pixel-accent) !important;
    background: rgba(30, 20, 40, 0.75) !important;
}

/* --- 4. 顶部元素居中 & 头像优化 --- */
.mes_header {
    display: flex !important;
    flex-direction: column !important;
    align-items: center !important;
    width: 100% !important;
    margin-bottom: 20px !important;
}

.avatar img {
    width: 60px !important;  /* 调小头像 */
    height: 60px !important; /* 保持正方形 */
    border: 2px solid var(--pixel-border) !important; /* 稍微减薄边框 */
    box-shadow: 3px 3px 0px #000, 5px 5px 0px var(--pixel-border); /* 匹配小尺寸的阴影位移 */
    margin-bottom: 12px;
}

.ch_name {
    font-size: 1.3em !important;
    letter-spacing: 2px;
    color: var(--pixel-border) !important;
    text-shadow: 3px 3px 0px #000;
}

/* --- 5. 消息文本 --- */
.mes_text {
    width: 100% !important;
    max-width: 1000px;
    color: var(--pixel-text) !important;
    font-size: 1.1em !important;
    line-height: 1.8;
    text-align: left !important;
    padding: 20px 0;
    border-top: 2px dashed rgba(79, 211, 196, 0.3);
}

/* --- 6. 输入区域调整 --- */
#send_form {
    background: var(--glass-bg) !important;
    backdrop-filter: var(--glass-heavy) !important;
    border-top: 4px solid var(--pixel-border) !important;
    padding: 20px 10% !important;
    box-shadow: 0 -10px 20px rgba(0,0,0,0.4);
}

#send_textarea {
    background: rgba(0, 0, 0, 0.4) !important;
    border: 2px solid var(--pixel-border) !important;
    color: var(--pixel-text) !important;
    font-family: 'Courier New', monospace;
    padding: 12px !important;
}

#send_textarea:focus {
    border-color: var(--pixel-accent) !important;
    box-shadow: 0 0 15px var(--pixel-accent);
}

#send_but {
    background: var(--pixel-border) !important;
    color: #000 !important;
    font-weight: bold !important;
    border-radius: 0 !important;
    clip-path: polygon(10% 0, 100% 0, 90% 100%, 0 100%);
}

em { color: var(--pixel-border) !important; font-style: italic; }
u { color: var(--pixel-accent) !important; text-decoration: underline dotted; }

@media screen and (max-width: 800px) {
    .mes { width: 98% !important; padding: 15px !important; }
    #send_form { padding: 10px 2% !important; }
}
